func TestDefaultConfig_ReturnsValidConfig(t *testing.T) {
	config := DefaultConfig()

	// Default config should pass validation
	err := config.Validate()
	assert.NoError(t, err)

	// Verify expected defaults
	assert.NotNil(t, config.Ports)
	assert.NotEmpty(t, config.Ports.Inputs)
	assert.NotEmpty(t, config.Ports.Outputs)
	assert.Equal(t, 30*time.Second, config.DetectionInterval())
	assert.Equal(t, false, config.EnableLLM)
	assert.Equal(t, 3, config.MinCommunitySize)
	assert.Equal(t, 100, config.MaxIterations)

	// Verify required inputs - MUST be kv-watch, NOT timer
	inputs := config.Ports.Inputs
	assert.GreaterOrEqual(t, len(inputs), 1, "should have at least 1 input")

	// Verify ENTITY_STATES kv-watch input
	hasEntityWatch := false
	for _, in := range inputs {
		if in.Subject == "ENTITY_STATES" && in.Type == "kv-watch" {
			hasEntityWatch = true
			break
		}
	}
	assert.True(t, hasEntityWatch, "should have ENTITY_STATES kv-watch input (NOT timer port)")

	// Verify required outputs
	outputs := config.Ports.Outputs
	assert.GreaterOrEqual(t, len(outputs), 1, "should have at least 1 output")

	// Verify COMMUNITY_INDEX output
	hasCommunityIndex := false
	for _, out := range outputs {
		if out.Subject == "COMMUNITY_INDEX" {
			hasCommunityIndex = true
			break
		}
	}
	assert.True(t, hasCommunityIndex, "should have COMMUNITY_INDEX output")
}

