func TestComponent_MultipleConfigValidations(t *testing.T) {
	tests := []struct {
		name      string
		config    Config
		shouldErr bool
	}{
		{
			name: "valid minimal",
			config: Config{
				Ports: &component.PortConfig{
					Inputs: []component.PortDefinition{
						{Name: "entity_watch", Type: "kv-watch", Subject: "ENTITY_STATES"},
					},
					Outputs: []component.PortDefinition{
						{Name: "communities", Type: "kv-write", Subject: "COMMUNITY_INDEX"},
					},
				},
				DetectionIntervalStr: "30s",
				MinCommunitySize:     3,
				MaxIterations:        100,
			},
			shouldErr: false,
		},
		{
			name: "valid with LLM",
			config: Config{
				Ports: &component.PortConfig{
					Inputs: []component.PortDefinition{
						{Name: "entity_watch", Type: "kv-watch", Subject: "ENTITY_STATES"},
					},
					Outputs: []component.PortDefinition{
						{Name: "communities", Type: "kv-write", Subject: "COMMUNITY_INDEX"},
					},
				},
				DetectionIntervalStr: "30s",
				EnableLLM:            true,
				LLMEndpoint:          "http://localhost:8080",
				MinCommunitySize:     3,
				MaxIterations:        100,
			},
			shouldErr: false,
		},
		{
			name: "invalid - LLM without endpoint",
			config: Config{
				Ports: &component.PortConfig{
					Inputs: []component.PortDefinition{
						{Name: "entity_watch", Type: "kv-watch", Subject: "ENTITY_STATES"},
					},
					Outputs: []component.PortDefinition{
						{Name: "communities", Type: "kv-write", Subject: "COMMUNITY_INDEX"},
					},
				},
				DetectionIntervalStr: "30s",
				EnableLLM:            true,
				MinCommunitySize:     3,
				MaxIterations:        100,
			},
			shouldErr: true,
		},
		{
			name: "invalid - zero interval",
			config: Config{
				Ports: &component.PortConfig{
					Inputs: []component.PortDefinition{
						{Name: "entity_watch", Type: "kv-watch", Subject: "ENTITY_STATES"},
					},
					Outputs: []component.PortDefinition{
						{Name: "communities", Type: "kv-write", Subject: "COMMUNITY_INDEX"},
					},
				},
				DetectionIntervalStr: "", // empty string results in zero duration
				MinCommunitySize:     3,
				MaxIterations:        100,
			},
			shouldErr: true,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			// Apply defaults to parse duration strings (except for zero interval test)
			if tt.config.DetectionIntervalStr != "" {
				tt.config.ApplyDefaults()
			}
			err := tt.config.Validate()
			if tt.shouldErr {
				assert.Error(t, err)
			} else {
				assert.NoError(t, err)
			}
		})
	}
}

